function SetListLegajos()
{
	if (Ctrl('listlegajos').GetXValue() == "")
	{
		Ctrl('leg_desde1').SetXValue("");
		Ctrl('leg_desde2').SetXValue("");
		Ctrl('leg_desde3').SetXValue("");
		Ctrl('leg_hasta1').SetXValue("");
		Ctrl('leg_hasta2').SetXValue("");
		Ctrl('leg_hasta3').SetXValue("");
		Ctrl('leg_list').SetXValue("");
		return true;
	}

	//valiado los caracteres ingresados
	if (!/^([0-9,\-])*$/.test(Ctrl('listlegajos').GetXValue()))	
	{
		alert('Caracteres invalidos');
		return false;
	} 

	//valido la cantidad de intervalos
	var cantInterval = Ctrl('listlegajos').GetXValue().split("-");
	if(cantInterval.length > 4)
	{
		alert('Se permiten 3 intervalos como máximo');
		return false;
	}	
	var legMembers = Ctrl('listlegajos').GetXValue().split(",");
	var leglist = "";
	var crango = 1;
	var leg_desde1 = "";
	var leg_desde2 = "";
	var leg_desde3 = "";
	var leg_hasta1 = "";
	var leg_hasta2 = "";
	var leg_hasta3 = "";

	for (i=0; i<legMembers.length; i++)
	{
		if(legMembers[i] == '')
		{
			alert('Caracteres invalidos');
			return false;
		}

		if(legMembers[i].match('-'))
		{			
			var auxarrg = legMembers[i].split("-");			

			//Valida los rangos
			if(auxarrg[0] == '-' || auxarrg[0] == '' || auxarrg[0] == ',')
			{
				alert('Caracteres invalidos');
				return false;
			}
			if(auxarrg[1] == '-' || auxarrg[1] == '' || auxarrg[1] == ',')
			{
				alert('Caracteres invalidos');
				return false;
			}

			if (crango == 1)				
			{
					leg_desde1 = auxarrg[0];
					leg_hasta1 = auxarrg[1];					
			}
			if (crango == 2)				
			{
					leg_desde2 = auxarrg[0];
					leg_hasta2 = auxarrg[1];
			}
			if (crango == 3)				
			{
					leg_desde3 = auxarrg[0];
					leg_hasta3 = auxarrg[1];
			}
			crango++
		}
		else
		{
			if(leglist == "")
				leglist += legMembers[i];
			else
				leglist += ',' + legMembers[i];			
		}		
	}
	Ctrl('leg_desde1').SetXValue(leg_desde1);
	Ctrl('leg_desde2').SetXValue(leg_desde2);
	Ctrl('leg_desde3').SetXValue(leg_desde3);
	Ctrl('leg_hasta1').SetXValue(leg_hasta1);
	Ctrl('leg_hasta2').SetXValue(leg_hasta2);
	Ctrl('leg_hasta3').SetXValue(leg_hasta3);	
	Ctrl('leg_list').SetXValue(leglist);	
	return true;
}

//Ejecuta el Query Seleccionado y devuelve un ARRAY con el resultado
function exec_qry()
{
	var np, nSQL, i;           

	var id = Ctrl('empresa').GetXValue(); 

	var param = "<DATA id=\""+id+"\" />";       	 

  np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	var qry = Ctrl("main").getResource("qry_empresas");

	var qryMembers = qry.split("##");
	for (i=1; i<qryMembers.length; i+=2)
	{
		if (Ctrl(qryMembers[i]).m_Required && Ctrl(qryMembers[i]).GetXValue()=="")
		{
			alert("El valor es requerido");
			Ctrl(qryMembers[i]).SetFocus();
			return null;
		}				

		qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
	}

  qry = qryMembers.join("");
  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(qry);

  var result = nSQL.Get(qry, param);
 	var resultArray = string2array(result);
 	// Ejecuta query EXTERNO
 	if (Ctrl("main").getResource("qry_externo"))
 	{
 		qry = Ctrl("main").getResource("qry_externo");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery Externo:\n" + qry);
	  result = nSQL.Get(qry, "");
	  var auxResult = string2array(result);
	  intersect(resultArray, auxResult);
	}
	// Ejecuta query de ATRIBUTOS EXTERNOS
 	if (Ctrl("main").getResource("qry_externo_attr"))
 	{
 		qry = Ctrl("main").getResource("qry_externo_attr");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  if (Ctrl("DEBUG")) Ctrl("DEBUG").SetXValue(Ctrl("DEBUG").GetXValue() + "\n\nQuery de Atributos Externos:\n" + qry);
	  result = nSQL.Get(qry, array2string(resultArray));
	  resultArray = string2array(result);
	}

  return resultArray;
}

function init_qry(strxml)
{
	var np, nSQL, result;

	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	// Ejecuta query de ATRIBUTOS EXTERNOS
 	if (Ctrl("main").getResource("qry_externo_attr"))
 	{
 		var qry = Ctrl("main").getResource("qry_externo_attr");
 		qryMembers = qry.split("##");
		for (i=1; i<qryMembers.length; i+=2)
		{
			qryMembers[i]=EncodeXML(Ctrl(qryMembers[i]).GetXValue());
		}
	  qry = qryMembers.join("");
	  result = nSQL.Get(qry, strxml);
	  var resultArray = string2array(result);
	}
	else
	{
		var qry = Ctrl("main").getResource("qry");
  	result = nSQL.Get(qry, strxml);
 		var resultArray = string2array(result);
 	}

  return resultArray;
}

//Agrega al Array A los elementos del Array B
function union(arrayA, arrayB)
{
	var key;
	for (key in arrayB)
		arrayA[key]=arrayB[key];
}

//Elimina del Array A los elementos del Array B
function remove(arrayA, arrayB)
{
	var key;
	for (key in arrayB)
		if (arrayA[key])
			delete arrayA[key];
}

//Elimina del Array A los elementos que no estan en el Array B
function intersect(arrayA, arrayB)
{
	var key;
	for (key in arrayA)
		if (arrayB[key]?false:true)
			delete arrayA[key];
}

//Transforma un Array a un XML(tipo STRING)
function array2string(arr)
{
	var retval = "";
	var key;
	for (key in arr)
	{
		retval+=ELE2String(arr[key].associatedELE);
	}

	return "<ROWS>"+retval+"</ROWS>";
}


function array2stringcustom(arr, eleroot, elechild)
{
	var key;
	var str ="<"+eleroot+">";
	for (key in arr) str+='<'+elechild+' id="'+key.substr(1)+'" />';
	str+="</"+eleroot+">";
	return str;
}              


//Transaforma un XML(tipo STRING) en ARRAY
function string2array(str)
{
	var arr = new Array();
	var auxXml = new nomadDOM(str);

	for (i=0; i<auxXml.Child.length; i++)
	{
		arr["k" + auxXml.Child[i].id]=auxXml.Child[i];
	}
	return arr;
}

//Function para activar y desactivar Botones
function enable_buttons()
{                                                                 
	if (Ctrl("list1"))
	{
		CtrlEnabled("DEL"    , Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("DEL_ALL", Ctrl("list1").TotalRowsCount()?true:false);

		CtrlEnabled("list1_Clear" , Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("list1_Delete", Ctrl("list1").TotalRowsCount()?true:false);
		CtrlEnabled("list1_UnMark", Ctrl("list1").TotalRowsCount()?true:false);
	}
	if (Ctrl("list2"))
	{
		CtrlEnabled("ADD"    , Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("ADD_ALL", Ctrl("list2").TotalRowsCount()?true:false);

		CtrlEnabled("list2_Clear" , Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("list2_Delete", Ctrl("list2").TotalRowsCount()?true:false);
		CtrlEnabled("list2_UnMark", Ctrl("list2").TotalRowsCount()?true:false);
	}
	enable_custom_buttons();
}

function enable_custom_buttons()
{
}

//Actualiza la lista con el nuevo ARRAY
function refreshList(strList, arr)
{
	Ctrl(strList).processResult(array2string(arr));
	enable_buttons();
}

function load()    { NomadTimeout("internal_load();",100,"Cargando la Lista..."); }
function filter()  { NomadTimeout("internal_filter();",100,"Filtrando la Lista..."); }
function loadadd() { NomadTimeout("internal_loadadd();",100,"Agregando en la Lista..."); }        
function find()    { NomadTimeout("internal_find();",100,"Buscando en la lista..."); }        

function internal_load()
{ 
	if(Ctrl('listlegajos'))
	{
	  if(!SetListLegajos()) return false;
	}
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;

	arrB = auxArr; 
	remove(arrB, arrA);	
	refreshList("list2", arrB);
}

function internal_filter()
{
  if(Ctrl('listlegajos'))
	{
		if(!SetListLegajos()) return false;
	}
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	intersect(arrB, auxArr);	
	refreshList("list2", arrB);
}

function internal_loadadd()
{
  if(Ctrl('listlegajos'))
	{
	  if(!SetListLegajos()) return false;  	
	}
  var auxArr;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	remove(auxArr, arrA);		
	union(arrB, auxArr);
	refreshList("list2", arrB);
}

function internal_find()
{
  if(Ctrl('listlegajos'))
	{
		if(!SetListLegajos()) return false;  	
	}
  var auxArr;
  var key;
	auxArr = exec_qry();
	if (auxArr==null) return;  

	intersect(auxArr, arrB);
	key="";
	for (key in auxArr) break;
	if (key!="") 
		Ctrl("list2").SetXValue(key.substr(1));
	else
		alert("No se encontro ningun registro.");
}

function ONLOAD()
{                
	arrA = new Array();
	arrB = new Array();
	ONLOAD_custom();
	enable_buttons();

	if (Ctrl("main").GetLastDoc("ARRA"))
	{                                
		arrA=init_qry(ELE2String(Ctrl("main").GetLastDoc("ARRA")));
		refreshList("list1", arrA);
	}

	if (Ctrl("main").GetLastDoc("ARRB"))
	{    
		if (Ctrl("main").GetLastDoc("ARRB").childNodes.length<100)
			arrB=init_qry(ELE2String(Ctrl("main").GetLastDoc("ARRB")));

		refreshList("list2", arrB);
	}

	if (Ctrl("l_afiliado_sind")) habilitarAfiliado();
}

