//Envio el XML al Server
function sendToServer()
{
	proxy=new NomadProxy();
	proxy.StoreService().SetSessionStore("FILTERDATA", array2string(arrA));
	return true;
}

function ACCEPT()
{
	sendToServer();
}

function CANCEL()
{
	Ctrl("main").DoEvent("CANCEL");
}

function EncodeXML(xmlin)
{	
	xmlin = Replace(xmlin, "&", "&amp;");
	xmlin = Replace(xmlin, "<", "&lt;");
	xmlin = Replace(xmlin, ">", "&gt;");
	xmlin = Replace(xmlin, "'", "´");
	xmlin = Replace(xmlin, '"', "&quot;");

	return xmlin;
}

		function SendToServer()
{       
	GetProxy().StoreService().SetUserStore("FILTERDATA", array2stringcustom(arrB, "ROWS", "ROW"));
	return true;
}

function Filtrar()
{
	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay empresas filtradas.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>100)
 	{             
 		alert("Hay demasiados registros seleccionados, afine la búsqueda.");
 		return false;
 	} 

 	if(Ctrl('fecha_reporte').GetXValue() == "")
 	{
 	 alert("La fecha de reporte es requerida.");
 	 return false;
 	}  

 	var param = '<DATOS fecha=\"'+Ctrl('fecha_reporte').GetXValue()+'\" checkOT=\"'+Ctrl('checkOT').GetXValue()+'" IDs=\"';

  param = param + Ctrl("list2").GetAttrValue(0,'id');                              
  for(var i=1;i<Ctrl("list2").RowsCount();i++)
  {
    var id = Ctrl("list2").GetAttrValue(i,'id');
    param = param+', '+id
  }

  param = param+'"/>'  

  //Invoco al Reporte de Reclamos
  getFormInMain("NucleusRH.Base.Control_Contratistas.Reportes.VehiculosHabilitados.flow", "Reporte", param, false);

	//SendToServer();
	//Ctrl("main").DoEvent("FILTER");
}

